use crate::api::client::ApiClient;
use crate::models::{ResultWithDefaultError, TimeEntry};
use crate::utilities::normalize_time_entry_list_filters;
use std::collections::HashMap;

const BILLING_UNIT_SECONDS: i64 = 15 * 60;

pub struct BillCommand;

impl BillCommand {
    pub async fn execute(
        api_client: impl ApiClient,
        since: Option<String>,
        until: Option<String>,
    ) -> ResultWithDefaultError<()> {
        let (since, until) = normalize_time_entry_list_filters(since, until)?;
        let entries = api_client.get_time_entries_filtered(since, until).await?;
        let totals = aggregate_billable_entries(&entries);

        if totals.is_empty() {
            println!("(no data)");
            return Ok(());
        }

        let mut totals: Vec<_> = totals.into_iter().collect();
        totals.sort_by(|(left_name, left_seconds), (right_name, right_seconds)| {
            right_seconds
                .cmp(left_seconds)
                .then_with(|| left_name.cmp(right_name))
        });

        let total_seconds: i64 = totals.iter().map(|(_, seconds)| seconds).sum();
        for (project, seconds) in totals {
            println!("{seconds}s  {project}");
        }
        println!("{total_seconds}s  Total");
        Ok(())
    }
}

fn aggregate_billable_entries(entries: &[TimeEntry]) -> HashMap<String, i64> {
    let mut totals = HashMap::new();
    for entry in entries {
        if !entry.billable || entry.is_running() {
            continue;
        }

        let billed_seconds = round_up_to_billing_unit(entry.duration);
        let project = entry
            .project
            .as_ref()
            .map(|project| project.name.clone())
            .unwrap_or_else(|| "No Project".to_string());
        *totals.entry(project).or_insert(0) += billed_seconds;
    }
    totals
}

fn round_up_to_billing_unit(seconds: i64) -> i64 {
    ((seconds + BILLING_UNIT_SECONDS - 1) / BILLING_UNIT_SECONDS) * BILLING_UNIT_SECONDS
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::models::{Project, TimeEntry};
    use chrono::{DateTime, NaiveDateTime, Utc};

    fn timestamp(seconds: i64) -> DateTime<Utc> {
        DateTime::from_utc(NaiveDateTime::from_timestamp_opt(seconds, 0).unwrap(), Utc)
    }

    fn entry(id: i64, seconds: i64, billable: bool, project: Option<&str>) -> TimeEntry {
        TimeEntry {
            id,
            description: String::new(),
            start: timestamp(0),
            stop: if seconds >= 0 {
                Some(timestamp(seconds))
            } else {
                None
            },
            duration: seconds,
            billable,
            workspace_id: 1,
            tags: vec![],
            project: project.map(|name| Project {
                id: 1,
                name: name.to_string(),
                workspace_id: 1,
                client: None,
                is_private: false,
                active: true,
                at: timestamp(0),
                created_at: timestamp(0),
                color: String::new(),
                billable: None,
            }),
            task: None,
            created_with: None,
        }
    }

    #[test]
    fn rounds_each_entry_before_aggregating_and_excludes_non_billable_or_running() {
        let entries = vec![
            entry(1, 7 * 60, true, Some("Alpha")),
            entry(2, 22 * 60, true, Some("Alpha")),
            entry(3, 60 * 60, false, Some("Alpha")),
            entry(4, -60, true, Some("Alpha")),
        ];

        let totals = aggregate_billable_entries(&entries);

        assert_eq!(totals.get("Alpha"), Some(&(45 * 60)));
    }

    #[test]
    fn uses_no_project_and_supports_project_sorting_rules() {
        let entries = vec![
            entry(1, 15 * 60, true, Some("Zulu")),
            entry(2, 15 * 60, true, Some("Alpha")),
            entry(3, 15 * 60, true, None),
        ];
        let mut totals: Vec<_> = aggregate_billable_entries(&entries).into_iter().collect();
        totals.sort_by(|(left_name, left_seconds), (right_name, right_seconds)| {
            right_seconds
                .cmp(left_seconds)
                .then_with(|| left_name.cmp(right_name))
        });

        assert_eq!(
            totals,
            vec![
                ("Alpha".to_string(), 900),
                ("No Project".to_string(), 900),
                ("Zulu".to_string(), 900),
            ]
        );
    }
